def find_circular_deps(dep_graph):
    cycles = []
    visited = set()

    def dfs(node, path, path_set):
        if node in path_set:
            cycle_start = path.index(node)
            cycle = path[cycle_start:] + [node]
            cycles.append(cycle)
            return
        if node in visited:
            return
        visited.add(node)
        path_set.add(node)
        path.append(node)
        for neighbor in dep_graph.get(node, []):
            dfs(neighbor, path, path_set)
        path.pop()
        path_set.remove(node)

    for node in dep_graph:
        visited.clear()
        dfs(node, [], set())

    # Deduplicate cycles by comparing sorted canonical forms
    unique = []
    seen_canonical = set()
    for cycle in cycles:
        loop = cycle[:-1]
        min_idx = loop.index(min(loop))
        canonical = tuple(loop[min_idx:] + loop[:min_idx])
        if canonical not in seen_canonical:
            seen_canonical.add(canonical)
            unique.append(cycle)
    return unique


def extract_imported_names(code_text):
    names = set()
    for line in code_text.strip().splitlines():
        line = line.strip()
        if line.startswith('from ') and ' import ' in line:
            after_import = line.split(' import ')[1]
            for name in after_import.split(','):
                name = name.strip()
                if ' as ' in name:
                    names.add(name.split(' as ')[1].strip())
                else:
                    names.add(name)
        elif line.startswith('import '):
            rest = line[7:].strip()
            if ' as ' in rest:
                names.add(rest.split(' as ')[1].strip())
            else:
                names.add(rest)
    return sorted(names)


def count_import_usage(code_text, module_name):
    import re
    count = 0
    for line in code_text.strip().splitlines():
        stripped = line.strip()
        if stripped.startswith('import ') or stripped.startswith('from '):
            continue
        count += len(re.findall(r'\b' + re.escape(module_name) + r'\b', line))
    return count


def suggest_import_cleanup(imports_list, used_names):
    unused = [name for name in imports_list if name not in used_names]
    return sorted(unused)
